import React, { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Formik, Form } from 'formik';
import * as Yup from 'yup';
import { useAuth } from '../../contexts/AuthContext';
import { useFormContext } from '../../contexts/FormContext';
import { Card, CardContent, CardHeader, CardTitle } from '../../components/ui/card';
import { Button } from '../../components/ui/button';
import { Input } from '../../components/ui/input';
import { Label } from '../../components/ui/label';
import { Textarea } from '../../components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '../../components/ui/select';
import { Badge } from '../../components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '../../components/ui/avatar';
import { 
  Calendar, Clock, User, Stethoscope, MapPin, DollarSign, 
  CheckCircle, AlertCircle, ArrowLeft, Star
} from 'lucide-react';
import { toast } from 'sonner';
import { mockDoctors, getPatientInfo, getDoctorById, getAvailableSlots, bookAppointment } from '../../services/mockData';
import LoadingSpinner from '../../components/ui/LoadingSpinner';

// Validation Schema
const appointmentSchema = Yup.object().shape({
  doctorId: Yup.string().required('Please select a doctor'),
  appointmentDate: Yup.date()
    .required('Please select an appointment date')
    .min(new Date(), 'Cannot book appointments for past dates'),
  appointmentTime: Yup.string().required('Please select an appointment time'),
  appointmentType: Yup.string().required('Please select appointment type'),
  symptoms: Yup.string().required('Please describe your symptoms or reason for visit'),
  notes: Yup.string()
});

const AppointmentBooking = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const { getFieldProps, renderFormField } = useFormContext();
  
  const [patient, setPatient] = useState(null);
  const [selectedDoctor, setSelectedDoctor] = useState(null);
  const [availableSlots, setAvailableSlots] = useState([]);
  const [loading, setLoading] = useState(true);
  
  const isFromSearch = searchParams.get('fromSearch') === 'true';

  // Initial form values
  const initialValues = {
    doctorId: searchParams.get('doctorId') || '',
    appointmentDate: '',
    appointmentTime: '',
    appointmentType: 'consultation',
    symptoms: '',
    notes: ''
  };

  // Load initial data
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const patientData = await getPatientInfo();
        setPatient(patientData);
        
        const doctorId = searchParams.get('doctorId');
        if (doctorId) {
          const doctor = await getDoctorById(doctorId);
          setSelectedDoctor(doctor);
        }
      } catch (error) {
        console.error('Error loading data:', error);
        toast.error('Error loading appointment data');
      } finally {
        setLoading(false);
      }
    };
    
    loadData();
  }, [searchParams]);

  // Load available slots
  const loadSlots = async (doctorId, date) => {
    if (doctorId && date) {
      try {
        const slots = await getAvailableSlots(doctorId, date);
        setAvailableSlots(slots);
      } catch (error) {
        console.error('Error loading slots:', error);
        setAvailableSlots([]);
      }
    }
  };

  const handleDoctorChange = async (doctorId, setFieldValue) => {
    if (isFromSearch) {
      toast.error('Cannot change doctor when booking from search. Please start a new booking.');
      return;
    }
    
    const doctor = await getDoctorById(doctorId);
    setSelectedDoctor(doctor);
    setFieldValue('doctorId', doctorId);
    setFieldValue('appointmentTime', '');
    setAvailableSlots([]);
  };

  const handleSubmit = async (values, { setSubmitting }) => {
    try {
      const appointmentData = {
        ...values,
        patientId: patient.id,
        status: 'pending'
      };
      
      const result = await bookAppointment(appointmentData);
      
      if (result.success) {
        toast.success('Appointment booked successfully!', {
          description: 'You will receive a confirmation email shortly.'
        });
        
        setTimeout(() => {
          navigate(`/app/${user?.role}/dashboard`);
        }, 2000);
      }
    } catch (error) {
      console.error('Booking error:', error);
      toast.error('Failed to book appointment. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  const renderStars = (rating) => {
    const stars = [];
    const fullStars = Math.floor(rating);
    
    for (let i = 0; i < fullStars; i++) {
      stars.push(<Star key={i} className="w-4 h-4 fill-yellow-400 text-yellow-400" />);
    }
    
    if (rating % 1 !== 0) {
      stars.push(<Star key="half" className="w-4 h-4 fill-yellow-400/50 text-yellow-400" />);
    }
    
    return stars;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-96">
        <LoadingSpinner size="lg" text="Loading appointment booking..." />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center gap-4">
        <Button 
          variant="ghost" 
          size="sm" 
          onClick={() => navigate(`/app/${user?.role}/dashboard`)}
        >
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Dashboard
        </Button>
        <h1 className="text-2xl font-bold text-gray-900">Book Appointment</h1>
        {isFromSearch && (
          <Badge className="bg-blue-100 text-blue-800">
            Selected from Search
          </Badge>
        )}
      </div>

      <Formik
        initialValues={initialValues}
        validationSchema={appointmentSchema}
        onSubmit={handleSubmit}
        enableReinitialize
      >
        {({ values, setFieldValue, isSubmitting, errors, touched }) => (
          <Form>
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              {/* Main Booking Form */}
              <div className="lg:col-span-2">
                <Card>
                  <CardHeader>
                    <CardTitle className="flex items-center gap-2">
                      <Calendar className="w-5 h-5" />
                      Appointment Details
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-6">
                    {/* Patient Info */}
                    <div className="space-y-2">
                      <Label>Patient Information</Label>
                      <div className="p-3 bg-gray-50 border rounded-lg">
                        <div className="flex items-center gap-3">
                          <User className="w-5 h-5 text-gray-500" />
                          <div>
                            <p className="font-medium text-gray-900">{patient?.name}</p>
                            <p className="text-sm text-gray-600">{patient?.email}</p>
                            <p className="text-sm text-gray-600">{patient?.phone}</p>
                          </div>
                        </div>
                      </div>
                    </div>

                    {/* Doctor Selection */}
                    <div className="space-y-2">
                      <Label htmlFor="doctor">
                        Select Doctor *
                        {isFromSearch && (
                          <span className="text-xs text-gray-500 ml-2">
                            (Cannot change - selected from search)
                          </span>
                        )}
                      </Label>
                      {isFromSearch && selectedDoctor ? (
                        <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg">
                          <div className="flex items-center gap-3">
                            <Avatar className="w-10 h-10">
                              <AvatarImage src={selectedDoctor.avatar} />
                              <AvatarFallback>
                                {selectedDoctor.name.split(' ').map(n => n[0]).join('')}
                              </AvatarFallback>
                            </Avatar>
                            <div>
                              <p className="font-medium text-blue-900">{selectedDoctor.name}</p>
                              <p className="text-sm text-blue-700">{selectedDoctor.specialization}</p>
                            </div>
                          </div>
                        </div>
                      ) : (
                        <Select 
                          onValueChange={(value) => handleDoctorChange(value, setFieldValue)} 
                          value={values.doctorId}
                        >
                          <SelectTrigger className={errors.doctorId && touched.doctorId ? 'border-red-500' : ''}>
                            <SelectValue placeholder="Choose a doctor..." />
                          </SelectTrigger>
                          <SelectContent>
                            {mockDoctors.map((doctor) => (
                              <SelectItem key={doctor.id} value={doctor.id}>
                                <div className="flex items-center gap-3">
                                  <Avatar className="w-8 h-8">
                                    <AvatarImage src={doctor.avatar} />
                                    <AvatarFallback className="text-xs">
                                      {doctor.name.split(' ').map(n => n[0]).join('')}
                                    </AvatarFallback>
                                  </Avatar>
                                  <div>
                                    <p className="font-medium">{doctor.name}</p>
                                    <p className="text-sm text-gray-600">{doctor.specialization}</p>
                                  </div>
                                </div>
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                      )}
                      {errors.doctorId && touched.doctorId && (
                        <p className="text-sm text-red-600">{errors.doctorId}</p>
                      )}
                    </div>

                    {/* Date Selection */}
                    <div className="space-y-2">
                      <Label htmlFor="appointmentDate">Appointment Date *</Label>
                      <Input
                        type="date"
                        name="appointmentDate"
                        min={new Date().toISOString().split('T')[0]}
                        value={values.appointmentDate}
                        onChange={(e) => {
                          setFieldValue('appointmentDate', e.target.value);
                          setFieldValue('appointmentTime', '');
                          loadSlots(values.doctorId, e.target.value);
                        }}
                        className={errors.appointmentDate && touched.appointmentDate ? 'border-red-500' : ''}
                      />
                      {errors.appointmentDate && touched.appointmentDate && (
                        <p className="text-sm text-red-600">{errors.appointmentDate}</p>
                      )}
                    </div>

                    {/* Time Slot Selection */}
                    <div className="space-y-2">
                      <Label>Available Time Slots *</Label>
                      {!values.appointmentDate ? (
                        <p className="text-sm text-gray-500">Please select a date first</p>
                      ) : availableSlots.length === 0 ? (
                        <p className="text-sm text-red-600">No available slots for this date</p>
                      ) : (
                        <div className="grid grid-cols-3 md:grid-cols-4 gap-2">
                          {availableSlots.map((slot) => (
                            <Button
                              key={slot}
                              type="button"
                              variant={values.appointmentTime === slot ? "default" : "outline"}
                              size="sm"
                              onClick={() => setFieldValue('appointmentTime', slot)}
                              className={`${
                                values.appointmentTime === slot 
                                  ? 'bg-blue-600 text-white' 
                                  : 'hover:bg-blue-50'
                              }`}
                            >
                              <Clock className="w-4 h-4 mr-1" />
                              {slot}
                            </Button>
                          ))}
                        </div>
                      )}
                      {errors.appointmentTime && touched.appointmentTime && (
                        <p className="text-sm text-red-600">{errors.appointmentTime}</p>
                      )}
                    </div>

                    {/* Appointment Type */}
                    <div className="space-y-2">
                      <Label>Appointment Type</Label>
                      <Select 
                        onValueChange={(value) => setFieldValue('appointmentType', value)} 
                        value={values.appointmentType}
                      >
                        <SelectTrigger>
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="consultation">Consultation</SelectItem>
                          <SelectItem value="follow-up">Follow-up</SelectItem>
                          <SelectItem value="check-up">Check-up</SelectItem>
                          <SelectItem value="emergency">Emergency</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    {/* Symptoms */}
                    <div className="space-y-2">
                      <Label htmlFor="symptoms">Symptoms / Reason for Visit *</Label>
                      <Textarea
                        name="symptoms"
                        placeholder="Please describe your symptoms or reason for the appointment..."
                        value={values.symptoms}
                        onChange={(e) => setFieldValue('symptoms', e.target.value)}
                        className={errors.symptoms && touched.symptoms ? 'border-red-500' : ''}
                        rows={3}
                      />
                      {errors.symptoms && touched.symptoms && (
                        <p className="text-sm text-red-600">{errors.symptoms}</p>
                      )}
                    </div>

                    {/* Notes */}
                    <div className="space-y-2">
                      <Label htmlFor="notes">Additional Notes (Optional)</Label>
                      <Textarea
                        name="notes"
                        placeholder="Any additional information you'd like the doctor to know..."
                        value={values.notes}
                        onChange={(e) => setFieldValue('notes', e.target.value)}
                        rows={2}
                      />
                    </div>

                    {/* Submit Button */}
                    <Button
                      type="submit"
                      disabled={isSubmitting}
                      className="w-full bg-blue-600 hover:bg-blue-700 text-white"
                    >
                      {isSubmitting ? (
                        <LoadingSpinner size="sm" />
                      ) : (
                        <>
                          <CheckCircle className="w-4 h-4 mr-2" />
                          Book Appointment
                        </>
                      )}
                    </Button>
                  </CardContent>
                </Card>
              </div>

              {/* Doctor Info Sidebar */}
              <div className="space-y-6">
                {selectedDoctor && (
                  <Card>
                    <CardHeader>
                      <CardTitle className="text-lg">Doctor Information</CardTitle>
                    </CardHeader>
                    <CardContent className="space-y-4">
                      <div className="flex items-center gap-3">
                        <Avatar className="w-16 h-16 ring-2 ring-blue-100">
                          <AvatarImage src={selectedDoctor.avatar} />
                          <AvatarFallback className="bg-blue-100 text-blue-600 text-lg font-semibold">
                            {selectedDoctor.name.split(' ').map(n => n[0]).join('')}
                          </AvatarFallback>
                        </Avatar>
                        <div>
                          <h3 className="font-semibold text-gray-900">{selectedDoctor.name}</h3>
                          <p className="text-sm text-gray-600">{selectedDoctor.specialization}</p>
                          <div className="flex items-center gap-1 mt-1">
                            {renderStars(selectedDoctor.rating)}
                            <span className="text-sm text-gray-600 ml-1">
                              ({selectedDoctor.reviews} reviews)
                            </span>
                          </div>
                        </div>
                      </div>

                      <div className="space-y-3 text-sm">
                        <div className="flex items-center gap-2">
                          <Stethoscope className="w-4 h-4 text-gray-500" />
                          <span>{selectedDoctor.experience} years experience</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <MapPin className="w-4 h-4 text-gray-500" />
                          <span>{selectedDoctor.hospital}</span>
                        </div>
                        <div className="flex items-center gap-2">
                          <DollarSign className="w-4 h-4 text-gray-500" />
                          <span>Consultation Fee: ${selectedDoctor.consultationFee}</span>
                        </div>
                      </div>

                      <div>
                        <p className="text-sm text-gray-600">{selectedDoctor.about}</p>
                      </div>

                      <div className="flex flex-wrap gap-1">
                        {selectedDoctor.degrees.map((degree, index) => (
                          <Badge key={index} variant="outline" className="text-xs">
                            {degree}
                          </Badge>
                        ))}
                      </div>
                    </CardContent>
                  </Card>
                )}

                {/* Booking Info */}
                <Card>
                  <CardHeader>
                    <CardTitle className="text-lg flex items-center gap-2">
                      <AlertCircle className="w-5 h-5" />
                      Booking Information
                    </CardTitle>
                  </CardHeader>
                  <CardContent className="space-y-3 text-sm text-gray-600">
                    <div className="flex items-start gap-2">
                      <CheckCircle className="w-4 h-4 text-green-500 mt-0.5" />
                      <span>Appointments are subject to doctor availability</span>
                    </div>
                    <div className="flex items-start gap-2">
                      <CheckCircle className="w-4 h-4 text-green-500 mt-0.5" />
                      <span>You'll receive email confirmation within 24 hours</span>
                    </div>
                    <div className="flex items-start gap-2">
                      <CheckCircle className="w-4 h-4 text-green-500 mt-0.5" />
                      <span>Please arrive 15 minutes early for your appointment</span>
                    </div>
                    <div className="flex items-start gap-2">
                      <AlertCircle className="w-4 h-4 text-amber-500 mt-0.5" />
                      <span>Cancellations must be made at least 24 hours in advance</span>
                    </div>
                  </CardContent>
                </Card>
              </div>
            </div>
          </Form>
        )}
      </Formik>
    </div>
  );
};

export default AppointmentBooking;